$(document).ready(function(){var s=$("#menu"),e=$(".header__menu-toggle"),o=$(".menu__close");$(e).on("click",function(e){e.preventDefault(),s.toggleClass("active")}),$(o).on("click touchstart",function(e){e.preventDefault(),s.removeClass("active")}),$(".events").slick({autoplay:!0,arrows:!0,slidesToShow:4,slidesToScroll:1,infinite:!1,pauseOnFocus:!1,pauseOnHover:!1,responsive:[{breakpoint:991,settings:{slidesToShow:3}},{breakpoint:767,settings:{slidesToShow:2}},{breakpoint:575,settings:{slidesToShow:1}}]}),$(".gallery").slick()});